+import type { Trait } from '../trait/types';
+import type { World } from '../world/types';
+import type { Aspect, AspectInput, AspectRecord, AspectValue } from './types';
+
+export const $aspect = Symbol('aspect');
+
+let aspectId = -1;
+
+function flatten(inputs: AspectInput[]): Trait[] {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+    return traits;
+}
+
+export function createAspect<T extends [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<T> {
+    const traits = flatten(inputs);
+    const schema: Record<string, unknown> = {};
+    const fields = new Set<string>();
+
+    for (const trait of traits) {
+        if (isRelation(trait[$internal].relation)) {
+            throw new Error('Koota: relations cannot be constituents of an aspect');
+        }
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) {
+                throw new Error(`Koota: aspect constituents share the field "${field}"`);
+            }
+            fields.add(field);
+            schema[field] = trait.schema[field];
+        }
+    }
+
+    return Object.freeze({
+        [$aspect]: true as const,
+        id: aspectId--,
+        traits: Object.freeze(traits),
+        schema: Object.freeze(schema),
+    }) as unknown as Aspect<T>;
+}
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): AspectRecord<Aspect> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    return Object.assign({}, ...aspect.traits.map((trait) => getTrait(world, entity, trait)));
+}
+
+function valuesByTrait(aspect: Aspect, value: Record<string, unknown>) {
+    return aspect.traits.map((trait) => {
+        const fields = Object.keys(trait.schema);
+        const data: Record<string, unknown> = {};
+        for (const field of fields) if (field in value) data[field] = value[field];
+        return [trait, data] as const;
+    });
+}
+
+export function setAspect(
+    world: World,
+    entity: Entity,
+    aspect: Aspect,
+    value: AspectValue<Aspect>,
+    triggerChanged = true
+): void {
+    for (const [trait, data] of valuesByTrait(aspect, value)) {
+        if (Object.keys(data).length) setTrait(world, entity, trait, data, triggerChanged);
+    }
+}
+
+export function addAspect(
+    world: World,
+    entity: Entity,
+    aspect: Aspect,
+    value: AspectValue<Aspect> = {}
+): void {
+    for (const [trait, data] of valuesByTrait(aspect, value)) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, data]);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect): void {
+    removeTrait(world, entity, ...aspect.traits);
+}
